exercises.snippet:
class Editor:
    def __init__(self):
        self.text = ''
    def add(self, s):
        self.text += s
    def remove(self, n):
        self.text = self.text[:-n]

class Append:
    def __init__(self, e, p):
        self.e = e
        self.p = p
    def execute(self):
        self.e.add(self.p)
    def undo(self):
        self.e.remove(len(self.p))

e = Editor()
history = []
for cmd in [Append(e, 'ab'), Append(e, 'cd')]:
    cmd.execute()
    history.append(cmd)
history.pop().undo()
print(e.text)

exercises.solution:
def run_macro(commands):
    total = 0
    for c in commands:
        if c['op'] == 'add':
            total += c['value']
        elif c['op'] == 'sub':
            total -= c['value']
    return total
